#!/usr/bin/env python3

# Description: Matroska metadata writer with remuxing approach.
# Dependencies: yt-dlp, ffmpeg, mkvextract, mkvpropedit
# Usage: run in directory with .mkv / .webm / .mp4 files.
# AI Disclaimer: This script was generated by an AI language model.

import subprocess
import sys
import shutil
import json
import re
import os
import shlex
from xml.etree import ElementTree as ET
from xml.sax.saxutils import escape as xml_escape
import logging
from typing import cast

# Define ANSI color codes
COLOR_ERROR = "\033[0;31m"      # Red - Error messages
COLOR_SUCCESS = "\033[0;32m"    # Green - Success messages  
COLOR_INFO = "\033[0;33m"       # Yellow - Information messages
COLOR_PATH = "\033[0;34m"       # Blue - Files and paths
COLOR_DEBUG = "\033[0;35m"      # Magenta - Debug messages
COLOR_KEY = "\033[0;36m"        # Cyan - Keywords, IDs, field names
COLOR_RESET = "\033[0m"         # Reset all formatting

# Define block separator for output formatting
BLOCK_SEPARATOR = ""            # Empty line separator between file processing blocks

# Add a custom SUCCESS logging level between INFO (20) and WARNING (30)
SUCCESS_LEVEL = 25
logging.addLevelName(SUCCESS_LEVEL, "SUCCESS")


class ColoredLogger(logging.Logger):
    """
    Subclass of logging.Logger that exposes a `success` method so static
    type-checkers (like Pylance) can see it.
    """

    def success(self, msg, *args, **kwargs):
        if self.isEnabledFor(SUCCESS_LEVEL):
            # Use the internal _log API to emit at our custom level
            self._log(SUCCESS_LEVEL, msg, args, **kwargs)


# Make logging use our ColoredLogger class for newly created loggers
logging.setLoggerClass(ColoredLogger)


class ColoredFormatter(logging.Formatter):
    """
    Formatter that outputs colored prefixes only:
    - INFO: in yellow
    - SUCCESS: in green
    - ERROR: in red
    - DEBUG: in magenta
    The color is applied only to the prefix and immediately reset, so the message text
    remains in the terminal's default color.
    """

    def format(self, record):
        # Get the formatted message with params applied
        message = record.getMessage()

        # Determine prefix and color based on level (use uppercase prefixes)
        if record.levelno == SUCCESS_LEVEL:
            prefix_text = "[SUCCESS]"
            color = COLOR_SUCCESS
        elif record.levelno == logging.INFO:
            prefix_text = "[INFO]"
            color = COLOR_INFO
        elif record.levelno == logging.ERROR or record.levelno == logging.CRITICAL:
            prefix_text = "[ERROR]"
            color = COLOR_ERROR
        elif record.levelno == logging.DEBUG:
            prefix_text = "[DEBUG]"
            color = COLOR_DEBUG
        else:
            # For WARNING and other levels, default to the level name in yellow
            prefix_text = f"{record.levelname}:"
            color = COLOR_INFO

        # Apply color to prefix only, then reset before message text
        s = f"{color}{prefix_text}{COLOR_RESET} {message}"

        # Append exception info if present (uncolored)
        if record.exc_info:
            s = s + "\n" + self.formatException(record.exc_info)
        if record.stack_info:
            s = s + "\n" + record.stack_info

        return s


# Configure logger with colored output
# Use cast so static type checkers know this is a ColoredLogger with `.success`
logger = cast(ColoredLogger, logging.getLogger("matroska_metadata_writer"))
logger.setLevel(logging.INFO)  # default level; change to DEBUG to see debug messages
handler = logging.StreamHandler()
handler.setFormatter(ColoredFormatter())
logger.handlers = []
logger.addHandler(handler)
logger.propagate = False

REQUIRED_CMDS = ["yt-dlp", "ffmpeg", "mkvextract", "mkvpropedit"]

# Tags to keep from existing files (whitelist)
KEEP_TAGS = {"ENCODER", "HANDLER_NAME", "DURATION", "VENDOR_ID"}

# yt-dlp extra args (only extra arguments like cookies, player variant, etc.)
yt_dlp_extra_args = [
    "--cookies-from-browser", "firefox",
    "--extractor-args", "youtube:player_js_variant=tv"
]

# Allow override from environment (parsed with shlex so quoting works)
env_extra = os.environ.get("YT_DLP_EXTRA_ARGS")
if env_extra:
    try:
        yt_dlp_extra_args = shlex.split(env_extra)
        logger.info("Using YT_DLP_EXTRA_ARGS from environment: %s", yt_dlp_extra_args)
    except Exception as e:
        logger.warning("Failed to parse YT_DLP_EXTRA_ARGS env var, using defaults. Error: %s", e)


def die(msg, code=2):
    logger.error(msg)
    sys.exit(code)


def check_deps():
    missing = []
    for c in REQUIRED_CMDS:
        if shutil.which(c) is None:
            missing.append(c)
    if missing:
        die("Missing required commands: " + ", ".join(missing))


def is_supported_file(file):
    """Check if file is a supported media format."""
    ext = file.lower().rsplit(".", 1)[-1]
    return ext in ("mkv", "webm", "mp4")


def _parse_first_json(stdout):
    """Return the first JSON object found in stdout (handles multiple JSON lines)."""
    if not stdout:
        return None
    for line in stdout.splitlines():
        line = line.strip()
        if not line:
            continue
        try:
            return json.loads(line)
        except Exception:
            continue
    try:
        return json.loads(stdout)
    except Exception:
        return None


def extract_youtube_metadata(yid):
    """
    Use yt-dlp plus yt_dlp_extra_args to fetch metadata (-j). Returns dict with
    title/artist/description/date (ISO YYYY-MM-DD if upload_date available).
    """
    url = f"https://www.youtube.com/watch?v={yid}"
    cmd = ["yt-dlp"] + yt_dlp_extra_args + ["-j", url]

    try:
        proc = subprocess.run(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True, check=False)
    except FileNotFoundError:
        logger.error("yt-dlp not found on PATH")
        return None

    stdout = proc.stdout or ""
    stderr = proc.stderr or ""
    
    if proc.returncode != 0:
        logger.error("yt-dlp failed (rc=%s): %s", proc.returncode, stderr.strip())
        return None
        
    if stderr:
        logger.debug("yt-dlp stderr: %s", stderr.strip())

    parsed = _parse_first_json(stdout)
    if not parsed:
        logger.error("yt-dlp produced no usable JSON on stdout")
        return None

    # If a playlist-like object with "entries" was returned, take the first entry
    if isinstance(parsed, dict) and "entries" in parsed and parsed.get("entries"):
        parsed = parsed["entries"][0] or parsed

    j = parsed
    title = j.get("title") or ""
    artist = (
        j.get("uploader_id")
        or j.get("channel_id")
        or j.get("uploader")
        or j.get("channel")
        or j.get("creator")
        or ""
    )
    desc = j.get("description") or ""
    date_raw = j.get("upload_date") or j.get("release_date") or ""
    if re.match(r"^\d{8}$", date_raw):
        date = f"{date_raw[0:4]}-{date_raw[4:6]}-{date_raw[6:8]}"
    else:
        date = date_raw or ""
    
    logger.debug("yt-dlp JSON fetched: title=%s artist=%s date=%s", title or "<none>", artist or "<none>", date or "<none>")
    return {"title": title, "artist": artist, "description": desc, "date": date}


def create_backup(file_path):
    """Create backup file with .bk extension."""
    backup_path = f"{file_path}.bk"
    try:
        shutil.copy2(file_path, backup_path)
        logger.info(f"Backup created: {COLOR_PATH}%s{COLOR_RESET}", backup_path)
        return backup_path
    except Exception as e:
        logger.error("Failed to create backup: %s", e)
        return None


def restore_from_backup(backup_path, original_path):
    """Restore file from backup."""
    try:
        if os.path.exists(backup_path):
            shutil.copy2(backup_path, original_path)
            logger.info(f"Restored from backup: {COLOR_PATH}%s{COLOR_RESET}", original_path)
            return True
    except Exception as e:
        logger.error("Failed to restore from backup: %s", e)
    return False


def cleanup_files(*file_paths):
    """Clean up temporary and backup files."""
    for file_path in file_paths:
        try:
            if file_path and os.path.exists(file_path):
                os.remove(file_path)
                logger.debug(f"Cleaned up: {COLOR_PATH}%s{COLOR_RESET}", file_path)
        except Exception as e:
            logger.debug("Failed to cleanup %s: %s", file_path, e)


def get_output_filename(input_file):
    """Get output filename (always .mkv extension)."""
    base = re.sub(r'\.(mkv|webm|mp4)$', '', input_file, flags=re.IGNORECASE)
    return f"{base}.mkv"


def remux_to_mkv(input_file, output_file, metadata):
    """Remux input file to MKV with metadata."""
    try:
        cmd = ["ffmpeg", "-i", input_file, "-c", "copy", "-f", "matroska"]
        
        # Add YouTube metadata to container info (not tags)
        if metadata.get("title"):
            cmd.extend(["-metadata", f"title={metadata['title']}"])
        if metadata.get("artist"):
            cmd.extend(["-metadata", f"artist={metadata['artist']}"])
        if metadata.get("description"):
            cmd.extend(["-metadata", f"description={metadata['description']}"])
        if metadata.get("date"):
            cmd.extend(["-metadata", f"date={metadata['date']}"])
            
        cmd.append(output_file)
        
        result = subprocess.run(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)
        
        if result.returncode == 0:
            logger.success("File remuxed to MKV successfully")
            return True
        else:
            logger.error("ffmpeg failed (rc=%s): %s", result.returncode, result.stderr.strip())
            return False
            
    except Exception as e:
        logger.error("Exception during remux: %s", e)
        return False


def extract_existing_tags_to_file(video_file, tags_file):
    """Extract existing tags from video file to XML file using mkvextract."""
    try:
        result = subprocess.run(
            ["mkvextract", "tags", video_file],
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True
        )
        
        logger.debug("mkvextract rc=%s", result.returncode)
        if result.stderr:
            logger.debug("mkvextract stderr: %s", result.stderr.strip())

        # If stdout contains XML, write it regardless of returncode
        if result.stdout and ("<Tags" in result.stdout or "<?xml" in result.stdout):
            with open(tags_file, 'w', encoding='utf-8') as f:
                f.write(result.stdout)
            logger.info(f"Tags extracted to {COLOR_PATH}%s{COLOR_RESET}", tags_file)
            return True
        else:
            logger.debug("mkvextract produced no tags XML (rc=%s)", result.returncode)
            return False

    except Exception as e:
        logger.error("Exception in extract_existing_tags_to_file: %s", e)
        return False


def validate_xml_file(xml_file):
    """Validate that the XML file is well-formed."""
    try:
        if not os.path.exists(xml_file) or os.path.getsize(xml_file) == 0:
            return False
        ET.parse(xml_file)
        return True
    except Exception as e:
        logger.error(f"XML validation failed for {COLOR_PATH}%s{COLOR_RESET}: %s", xml_file, e)
        return False


def _localname(tag):
    """Return the localname of an XML tag even when namespaced."""
    if tag is None:
        return ""
    return tag.rsplit("}", 1)[-1] if "}" in tag else tag


def find_child_by_localname(parent, name):
    for c in list(parent):
        if _localname(c.tag) == name:
            return c
    return None


def parse_tags_file(path):
    """Parse XML tags file and return structured data."""
    if not os.path.exists(path) or os.path.getsize(path) == 0:
        return []
    try:
        tree = ET.parse(path)
    except Exception as e:
        logger.error(f"Failed to parse tags XML {COLOR_PATH}%s{COLOR_RESET}: %s", path, e)
        return []
        
    root = tree.getroot()
    tags = []
    
    # Find Tag elements regardless of namespace/localname
    for elem in root.iter():
        if _localname(elem.tag) != "Tag":
            continue
            
        tag = elem
        targets_el = find_child_by_localname(tag, "Targets")
        targets = []
        if targets_el is not None:
            for child in list(targets_el):
                tname = _localname(child.tag)
                targets.append((tname, child.text or ""))
                
        simples = []
        for simple in [c for c in list(tag) if _localname(c.tag) == "Simple"]:
            name_el = find_child_by_localname(simple, "Name")
            string_el = find_child_by_localname(simple, "String")
            taglang_el = find_child_by_localname(simple, "TagLanguageIETF")
            
            name = (name_el.text or "") if name_el is not None else ""
            val = ""
            if string_el is not None:
                # String may include CDATA or nested text nodes
                val = "".join(string_el.itertext())
            taglang = taglang_el.text if taglang_el is not None else None
            
            # Only keep whitelisted tags
            if name and name in KEEP_TAGS:
                simples.append((name, val, taglang))
                
        # Only include tags that have content after filtering
        if simples or targets:
            tags.append({"targets": targets, "simples": simples})
            
    return tags


def write_merged_tags_to_file(existing_tags, new_tags_map, outpath):
    """Write merged tags to XML file."""
    # Find or create global tag (empty targets)
    global_index = None
    for i, t in enumerate(existing_tags):
        if not t["targets"]:
            global_index = i
            break

    if global_index is None:
        # Insert new global tag at the beginning
        existing_tags.insert(0, {"targets": [], "simples": []})
        global_index = 0

    # Merge new metadata into the global tag
    existing_global = {name: (val, taglang) for (name, val, taglang) in existing_tags[global_index]["simples"]}

    # Update with new tags
    for k, v in new_tags_map.items():
        if v:  # Only add non-empty values
            existing_global[k] = (v, None)

    # Rebuild the global tag's simples
    merged_simples = []
    seen = set()

    # Preserve existing global tags, updating with new values where they exist
    for name, val, taglang in existing_tags[global_index]["simples"]:
        val2, taglang2 = existing_global.get(name, (val, taglang))
        merged_simples.append((name, val2, taglang2))
        seen.add(name)

    # Add any new tags that weren't in existing global tags
    for name in new_tags_map:
        if name not in seen and new_tags_map[name]:  # Only add non-empty values
            merged_simples.append((name, existing_global[name][0], existing_global[name][1]))

    # Update the global tag
    existing_tags[global_index]["simples"] = merged_simples

    # Write ALL tags (global + track-specific)
    try:
        with open(outpath, "w", encoding="utf-8") as f:
            f.write('<?xml version="1.0"?>\n')
            f.write('<Tags>\n')
            for tag in existing_tags:
                f.write('  <Tag>\n')
                if not tag["targets"]:
                    f.write('    <Targets />\n')
                else:
                    f.write('    <Targets>\n')
                    for tname, tval in tag["targets"]:
                        f.write(f'      <{tname}>{xml_escape(tval or "")}</{tname}>\n')
                    f.write('    </Targets>\n')
                for name, val, taglang in tag["simples"]:
                    f.write('    <Simple>\n')
                    f.write(f'      <Name>{xml_escape(name)}</Name>\n')
                    safe = (val or "").replace(']]>', ']]]]><![CDATA[>')
                    f.write(f'      <String><![CDATA[{safe}]]></String>\n')
                    if taglang:
                        f.write(f'      <TagLanguageIETF>{xml_escape(taglang)}</TagLanguageIETF>\n')
                    f.write('    </Simple>\n')
                f.write('  </Tag>\n')
            f.write('</Tags>\n')
        return True
    except Exception as e:
        logger.error("Failed to write merged tags XML: %s", e)
        return False


def apply_tags_from_file(video_file, tags_file):
    """Apply tags from XML file to video using mkvpropedit."""
    try:
        args = ["mkvpropedit", video_file, "--tags", f"all:{tags_file}"]
        result = subprocess.run(args, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)
        
        if result.returncode == 0:
            logger.success("Tags applied successfully")
            return True
        else:
            logger.error("mkvpropedit failed (rc=%s): %s", result.returncode, result.stderr.strip())
            return False
            
    except Exception as e:
        logger.error("Exception running mkvpropedit: %s", e)
        return False


def process_file(file):
    logger.info(f"Processing: {COLOR_PATH}%s{COLOR_RESET}", file)
    
    # Check if supported format
    if not is_supported_file(file):
        logger.warning(f"Unsupported format; skipping: {COLOR_PATH}%s{COLOR_RESET}", file)
        return False

    # Extract YouTube ID
    m = re.search(r'\[([A-Za-z0-9_-]{11})\]', file)
    if not m:
        logger.error(f"Could not extract YouTube ID from filename: {COLOR_PATH}%s{COLOR_RESET}", file)
        return False

    yid = m.group(1)
    logger.info(f"YouTube ID: {COLOR_KEY}%s{COLOR_RESET}", yid)

    # Initialize variables for cleanup
    backup_path = None
    wip_path = None
    output_path = None
    tags_file = None
    success = False  # Track success state

    try:
        # Step 1: Make backup
        logger.info("Step 1: Creating backup...")
        backup_path = create_backup(file)
        if not backup_path:
            logger.error("Failed to create backup, aborting")
            return False

        # Step 2: Rename file for processing
        logger.info("Step 2: Renaming file for processing...")
        wip_path = f"{file}.wip"
        try:
            os.rename(file, wip_path)
            logger.success(f"File renamed for processing: {COLOR_PATH}%s{COLOR_RESET}", wip_path)
        except Exception as e:
            logger.error("Failed to rename file for processing: %s", e)
            return False

        # Step 3: Fetch YouTube metadata
        logger.info("Step 3: Fetching YouTube metadata...")
        meta = extract_youtube_metadata(yid)
        if not meta:
            logger.error("Failed to fetch YouTube metadata, aborting")
            return False
            
        logger.info(f"Title: {COLOR_KEY}%s{COLOR_RESET}", meta.get('title') or '<none>')
        logger.info(f"Artist: {COLOR_KEY}%s{COLOR_RESET}", meta.get('artist') or '<none>')
        logger.info(f"Date: {COLOR_KEY}%s{COLOR_RESET}", meta.get('date') or '<none>')

        # Step 4: Remux to MKV
        logger.info("Step 4: Remuxing to MKV with container metadata...")
        output_path = get_output_filename(file)
        logger.info(f"Output file: {COLOR_PATH}%s{COLOR_RESET}", output_path)
        if not remux_to_mkv(wip_path, output_path, meta):
            logger.error("Remux failed, aborting")
            return False

        # Step 5: Extract tags from new MKV file
        logger.info("Step 5: Extracting existing tags from remuxed file...")
        safe_filename = re.sub(r'[^\w\-_.]', '_', output_path)
        tags_file = os.path.join('/tmp', f"{safe_filename}.tags.xml")
        
        if extract_existing_tags_to_file(output_path, tags_file):
            logger.success("Existing tags extracted successfully")
        else:
            logger.info("No existing tags found, creating empty tags file")
            with open(tags_file, 'w', encoding='utf-8') as f:
                f.write('<?xml version="1.0"?>\n<Tags>\n</Tags>\n')

        # Step 6: Validate extracted XML
        logger.info("Step 6: Validating extracted tags XML...")
        if not validate_xml_file(tags_file):
            logger.error("Extracted tags XML is invalid, aborting")
            return False
        logger.success("Extracted tags XML is valid")

        # Step 7: Parse existing tags
        logger.info("Step 7: Parsing existing tags (filtering whitelist)...")
        existing_tags = parse_tags_file(tags_file)
        
        # Count filtered tags
        total_tags = sum(len(tag["simples"]) for tag in existing_tags)
        logger.info(f"Found {COLOR_KEY}%d{COLOR_RESET} whitelisted tags to preserve", total_tags)
        
        # Prepare YouTube metadata
        new_tags = {
            "TITLE": meta.get("title", ""),
            "ARTIST": meta.get("artist", ""),
            "DESCRIPTION": meta.get("description", ""),
            "DATE_RELEASED": meta.get("date", "")
        }
        
        # Count non-empty YouTube tags
        youtube_tag_count = sum(1 for v in new_tags.values() if v)
        logger.info(f"Adding {COLOR_KEY}%d{COLOR_RESET} YouTube metadata tags", youtube_tag_count)

        # Step 8: Write merged tags
        logger.info("Step 8: Merging existing tags with YouTube metadata...")
        if not write_merged_tags_to_file(existing_tags, new_tags, tags_file):
            logger.error("Failed to write merged tags, aborting")
            return False
        logger.success("Tags merged and written to XML file")

        # Step 9: Validate merged XML
        logger.info("Step 9: Validating merged tags XML...")
        if not validate_xml_file(tags_file):
            logger.error("Merged tags XML is invalid, aborting")
            return False
        logger.success("Merged tags XML is valid")

        # Step 10: Apply tags to MKV
        logger.info("Step 10: Applying merged tags to MKV file...")
        if not apply_tags_from_file(output_path, tags_file):
            logger.error("Failed to apply tags, aborting")
            return False

        # Success: Clean up backup and work files
        logger.info("Cleaning up temporary files...")
        cleanup_files(backup_path, wip_path)
        logger.success(f"File processed successfully: {COLOR_PATH}%s{COLOR_RESET}", output_path)
        success = True  # Mark as successful
        return True

    except Exception as e:
        logger.error("Unexpected exception: %s", e)
        return False
    finally:
        # Clean up temp files
        if tags_file:
            cleanup_files(tags_file)
            
        # On failure only, restore from backup
        if not success and backup_path and os.path.exists(backup_path):
            logger.info("Restoring from backup due to failure...")
            if wip_path:
                cleanup_files(wip_path)
            if output_path and os.path.exists(output_path):
                cleanup_files(output_path)
            restore_from_backup(backup_path, file)
            cleanup_files(backup_path)


def main():
    check_deps()
    
    # Find all supported media files
    files = [f for f in os.listdir(".") 
             if os.path.isfile(f) and f.lower().endswith((".mkv", ".webm", ".mp4"))]
    
    if not files:
        logger.info("No supported media files found in current directory")
        return
        
    logger.info(f"Found {COLOR_KEY}%d{COLOR_RESET} supported files to process", len(files))
    
    # Track processing results
    success_count = 0
    failure_count = 0
    
    for fname in sorted(files):
        # Add separator before each file block (including the first one)
        print(BLOCK_SEPARATOR)
        
        # Process file and track result
        if process_file(fname):
            success_count += 1
        else:
            failure_count += 1
    
    # Show recap after all files are processed
    total_files = len(files)
    if total_files > 0:
        print(BLOCK_SEPARATOR)
        
        # Use appropriate grammar for singular/plural
        files_word = "file" if total_files == 1 else "files"
        success_word = "success" if success_count == 1 else "successes"
        failure_word = "failure" if failure_count == 1 else "failures"
        
        if failure_count == 0:
            logger.success(f"{COLOR_KEY}%d{COLOR_RESET} %s processed: {COLOR_SUCCESS}%d %s{COLOR_RESET}, {COLOR_KEY}%d %s{COLOR_RESET}",
                          total_files, files_word, success_count, success_word, failure_count, failure_word)
        else:
            logger.info(f"{COLOR_KEY}%d{COLOR_RESET} %s processed: {COLOR_SUCCESS}%d %s{COLOR_RESET}, {COLOR_ERROR}%d %s{COLOR_RESET}",
                       total_files, files_word, success_count, success_word, failure_count, failure_word)


if __name__ == "__main__":
    main()